// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>
#include <stdexcept>

#include "eas_common.hpp"

using namespace sqlgen;
using namespace sqlgen::literals;

// Helper: map table name to type
inline auto& table_type_map() {
  static std::map<std::string, std::string> m{
      {"Student", "Student"},
      {"Course", "Course"},
      {"Score", "Score"},
      {"Major", "Major"},
  };
  return m;
}

// --------------------- add_eas_records ---------------------
//
// Generic templated version is provided by the user; we implement it
// in a way that works with sqlgen and the defined types.
//
template <typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Verify table_name matches the type T
  const auto& m = table_type_map();
  auto it = m.find(table_name);
  if (it == m.end()) {
    throw std::runtime_error("Unknown table name: " + table_name);
  }

  // Simple runtime check: ensure mapping table_name ↔ T is consistent.
  // We keep it lightweight: just rely on the caller binding correct T.
  // If that is violated, sqlgen will fail at compile-time anyway.

  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto& conn = conn_res.value();

  for (const auto& rec : records) {
    auto r = sqlgen::insert(rec)(conn);
    if (!r) {
      throw std::runtime_error("Failed to insert record into " + table_name);
    }
  }
}

// --------------------- modify_eas_records_by_id ---------------------
//
// Modify a single column by primary key value.
// record_id is passed as std::string, converted according to table.
//
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const std::string& new_value_json) {
  using sqlgen::update;

  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto& conn = conn_res.value();

  if (table_name == "Student") {
    using T = Student;
    // Primary key type: Varchar<10> (string)
    T obj;
    // Set primary key
    obj.SNo = record_id;

    // We will construct a partial update using sqlgen's update API.
    // The column value is provided as JSON (string) to allow type parsing
    // via rfl/json. The user must ensure JSON format matches field type.

    auto u = sqlgen::update<T>()
                 .set(col_name, new_value_json)
                 .where("SNo = ?", record_id);

    auto res = u(conn);
    if (!res) {
      throw std::runtime_error("Failed to modify Student record");
    }
    return;
  }

  if (table_name == "Course") {
    using T = Course;
    // Primary key type: uint32_t, auto_incr
    uint32_t pk{};
    try {
      pk = static_cast<uint32_t>(std::stoul(record_id));
    } catch (...) {
      throw std::runtime_error("Invalid Course ID: " + record_id);
    }

    auto u = sqlgen::update<T>()
                 .set(col_name, new_value_json)
                 .where("CID = ?", pk);

    auto res = u(conn);
    if (!res) {
      throw std::runtime_error("Failed to modify Course record");
    }
    return;
  }

  if (table_name == "Score") {
    using T = Score;
    uint32_t pk{};
    try {
      pk = static_cast<uint32_t>(std::stoul(record_id));
    } catch (...) {
      throw std::runtime_error("Invalid Score ID: " + record_id);
    }

    auto u = sqlgen::update<T>()
                 .set(col_name, new_value_json)
                 .where("ScID = ?", pk);

    auto res = u(conn);
    if (!res) {
      throw std::runtime_error("Failed to modify Score record");
    }
    return;
  }

  if (table_name == "Major") {
    using T = Major;
    uint32_t pk{};
    try {
      pk = static_cast<uint32_t>(std::stoul(record_id));
    } catch (...) {
      throw std::runtime_error("Invalid Major ID: " + record_id);
    }

    auto u = sqlgen::update<T>()
                 .set(col_name, new_value_json)
                 .where("MID = ?", pk);

    auto res = u(conn);
    if (!res) {
      throw std::runtime_error("Failed to modify Major record");
    }
    return;
  }

  throw std::runtime_error("Unknown table name: " + table_name);
}

// --------------------- delete_eas_records_by_id ---------------------
//
// Delete a record by primary key
//
inline void delete_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id) {
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto& conn = conn_res.value();

  if (table_name == "Student") {
    using T = Student;
    std::string pk = record_id;

    auto d = sqlgen::remove<T>()
                 .where("SNo = ?", pk);

    auto res = d(conn);
    if (!res) {
      throw std::runtime_error("Failed to delete Student record");
    }
    return;
  }

  if (table_name == "Course") {
    using T = Course;
    uint32_t pk{};
    try {
      pk = static_cast<uint32_t>(std::stoul(record_id));
    } catch (...) {
      throw std::runtime_error("Invalid Course ID: " + record_id);
    }

    auto d = sqlgen::remove<T>()
                 .where("CID = ?", pk);

    auto res = d(conn);
    if (!res) {
      throw std::runtime_error("Failed to delete Course record");
    }
    return;
  }

  if (table_name == "Score") {
    using T = Score;
    uint32_t pk{};
    try {
      pk = static_cast<uint32_t>(std::stoul(record_id));
    } catch (...) {
      throw std::runtime_error("Invalid Score ID: " + record_id);
    }

    auto d = sqlgen::remove<T>()
                 .where("ScID = ?", pk);

    auto res = d(conn);
    if (!res) {
      throw std::runtime_error("Failed to delete Score record");
    }
    return;
  }

  if (table_name == "Major") {
    using T = Major;
    uint32_t pk{};
