/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 *
 * - Connects/creates SQLite database "test_db.sqlite"
 * - Drops Product table if it exists
 * - Creates Product table
 * - Begins a transaction
 * - Batch-inserts the products
 * - Commits if all inserts succeed, otherwise rolls back
 *
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  try {
    // Open SQLite database
    sqlgen::sqlite::connection db("test_db.sqlite");

    // Create a table wrapper for Product
    auto product_table = sqlgen::make_table<Product>(db, "Product");

    // Drop and recreate table to match requested behavior
    product_table.drop_if_exists();
    product_table.create();

    // Start transaction
    db.begin_transaction();

    // Perform batch insert (sqlgen handles efficient bulk insertion)
    product_table.insert_range(products);

    // Commit transaction if all went well
    db.commit();
    return true;
  } catch (...) {
    // On any error, attempt to roll back (if a transaction is active)
    try {
      // This will be a no-op if no transaction is active,
      // depending on sqlgen/sqlite implementation.
      sqlgen::sqlite::connection db("test_db.sqlite");
      db.rollback();
    } catch (...) {
      // Ignore rollback errors
    }
    return false;
  }
}

}  // namespace batch_insert_products
