#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Open a connection to the SQLite database.
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Create a SQLGen context bound to the connection.
  sqlgen::Context ctx(conn);

  // Begin a transaction for safety.
  auto tx = ctx.transaction();

  // Configure the context to operate on the User table.
  ctx.set_table<User>("User");

  // Reference date: users who have not logged in since 2025-01-01 should be removed,
  // i.e., last_login < '2025-01-01'.
  const auto cutoff = sqlgen::DateTime::from_string("2025-01-01 00:00:00");

  // Build and execute the delete query.
  //
  // This corresponds to:
  //   DELETE FROM User WHERE last_login < '2025-01-01 00:00:00';
  //
  // (Using the optional field accessor for last_login.)
  auto removed_count = ctx.remove<User>()
                           .where(&User::last_login < cutoff)
                           .exec();

  // Commit the transaction and return the operation result of commit.
  //
  // If the commit returns a result code, we return that; otherwise,
  // we assume commit succeeded and return the number of removed rows.
  auto commit_result = tx.commit();
  return commit_result;
}

} // namespace delete_inactive_users
