```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <chrono>
#include <iomanip>
#include <sstream>

namespace query_active_users_posts {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;

  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
  // 1. Connect to SQLite database "test_db.sqlite"
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // 2. Create User and Post tables
  {
    auto schema = sqlgen::make_schema(
        sqlgen::make_table<User>("User",
          sqlgen::make_column(&User::user_id, "user_id",
                              sqlgen::primary_key()),
          sqlgen::make_column(&User::username, "username",
                              sqlgen::not_null())),
        sqlgen::make_table<Post>("Post",
          sqlgen::make_column(&Post::post_id, "post_id",
                              sqlgen::primary_key()),
          sqlgen::make_column(&Post::user_id, "user_id"),
          sqlgen::make_column(&Post::created_at, "created_at",
                              sqlgen::not_null()))
    );

    sqlgen::sqlite::apply_schema(conn, schema);
  }

  // 3. Define a view representing:
  //
  //   SELECT DISTINCT u.user_id, u.username
  //   FROM User u
  //   INNER JOIN Post p ON u.user_id = p.user_id
  //   WHERE p.created_at >= DATE('2025-12-01')
  //     AND p.created_at <= DATE('2025-12-31');
  //
  // With sqlgen, we model this as a view table ActiveUser and a custom
  // SELECT statement that fills it.
  const char* view_sql =
      "CREATE TEMP VIEW IF NOT EXISTS ActiveUserView AS "
      "SELECT DISTINCT u.user_id AS user_id, u.username AS username "
      "FROM User u "
      "INNER JOIN Post p ON u.user_id = p.user_id "
      "WHERE p.created_at >= DATE('2025-12-01') "
      "  AND p.created_at <= DATE('2025-12-31');";

  {
    sqlgen::sqlite::Statement stmt(conn, view_sql);
    stmt.execute();
  }

  // 4. Query and return user information from the view
  std::vector<ActiveUser> result;
  {
    std::string select_sql =
        "SELECT user_id, username FROM ActiveUserView;";

    sqlgen::sqlite::Statement stmt(conn, select_sql);

    while (stmt.step()) {
      ActiveUser au;
      au.user_id = stmt.column_int(0);
      au.username = stmt.column_text(1);
      result.push_back(std::move(au));
    }
  }

  return result;
}

}  // namespace query_active_users_posts
