struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

inline std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;

  // Open connection to SQLite database "test_db.sqlite"
  sqlite::connection conn{"test_db.sqlite"};

  // Create schema for Course and Enrollment
  auto schema = make_schema(
      make_table<Course>("Course", &Course::course_id, &Course::title),
      make_table<Enrollment>("Enrollment",
                             &Enrollment::enrollment_id,
                             &Enrollment::course_id,
                             &Enrollment::grade));

  // Apply schema (creates tables if they do not exist)
  sqlite::migrate(conn, schema);

  // Define a view that corresponds to the aggregate query
  auto stats_view = make_view<CourseStatsView>(
      "course_enrollment_stats",
      "SELECT c.title AS title, "
      "       COUNT(e.enrollment_id) AS student_count, "
      "       AVG(e.grade) AS avg_grade "
      "FROM Course c "
      "LEFT JOIN Enrollment e ON c.course_id = e.course_id "
      "GROUP BY c.course_id, c.title");

  // Load the view (will create or replace it if supported; otherwise just use it)
  sqlite::create_view(conn, stats_view);

  // Query the view
  std::vector<CourseStatsView> rows =
      sqlite::select<CourseStatsView>(conn, stats_view);

  // Convert to CourseStats result type
  std::vector<CourseStats> result;
  result.reserve(rows.size());
  for (const auto &row : rows) {
    result.push_back(CourseStats{
        row.title,
        row.student_count,
        row.avg_grade,
    });
  }

  return result;
}

