      "LEFT JOIN Enrollment e ON c.course_id = e.course_id "
      "GROUP BY c.course_id, c.title");

  // Load the view (will create or replace it if supported; otherwise just use it)
  sqlite::create_view(conn, stats_view);

  // Query the view
  std::vector<CourseStatsView> rows =
      sqlite::select<CourseStatsView>(conn, stats_view);

  // Convert to CourseStats result type
  std::vector<CourseStats> result;
  result.reserve(rows.size());
  for (const auto &row : rows) {
    result.push_back(CourseStats{
        row.title,
        row.student_count,
        row.avg_grade,
    });
  }

  return result;
}

