std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
  using sqlgen::sqlite::Database;

  Database db{"test_db.sqlite"};

  // Start with a base SELECT * FROM Book
  auto query = sqlgen::select<Book>().from<Book>();

  // Dynamically add WHERE clauses based on filters
  if (filters.title_keyword.has_value()) {
    // Use LIKE for title search with wildcards
    std::string pattern = "%" + *filters.title_keyword + "%";
    query = query.where(&Book::title, sqlgen::Like, pattern);
