  if (filters.genre.has_value()) {
    query = query.where(&Book::genre, sqlgen::Equal, *filters.genre);
  }

  if (filters.max_price.has_value()) {
    query = query.where(&Book::price, sqlgen::LessEqual, *filters.max_price);
  }

  // Execute the query and return the results
  return db.execute(query);
