      std::cerr << "Warning: could not add column 'is_active': "
                << e.what() << std::endl;
    }

    return true;
  } catch (const std::exception &e) {
    // If we cannot connect or another fundamental error occurs, fail migration
    std::cerr << "Migration failed: " << e.what() << std::endl;
    return false;
  }
}

