  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
  // Nothing to do if no IDs are provided
  if (ids.empty()) {
    return true;
  }

  try {
    // Open SQLite database
    sqlgen::sqlite::Database db("test_db.sqlite");

    // Map the Document struct to the Document table
    sqlgen::Table<Document> documents(
        "Document",
        &Document::doc_id,
        &Document::title,
        &Document::is_deleted,
        &Document::deleted_at
    );

    // Attach table to the database
    db.attach(documents);

    // Begin transaction for atomicity and efficiency
    sqlgen::Transaction tx(db);

    // Prepare an UPDATE statement using a raw SQL statement with an IN clause.
    // We rely on sqlgen's parameter binding for the IDs.
    //
    // Reference SQL:
    // UPDATE Document
    // SET is_deleted = 1, deleted_at = CURRENT_TIMESTAMP
    // WHERE doc_id IN (?, ?, ...);

    // Build the IN clause placeholders based on number of ids
    std::string placeholders;
    placeholders.reserve(ids.size() * 2); // rough reserve
    for (size_t i = 0; i < ids.size(); ++i) {
      if (i > 0) {
        placeholders += ",";
      }
      placeholders += "?";
    }

    const std::string sql =
        "UPDATE Document "
        "SET is_deleted = 1, deleted_at = CURRENT_TIMESTAMP "
        "WHERE doc_id IN (" + placeholders + ")";

    sqlgen::Statement stmt = db.prepare(sql);

    // Bind all IDs
    int index = 1;
    for (int id : ids) {
      stmt.bind(index++, id);
    }

    // Execute the update
    stmt.execute();

    // Commit the transaction
    tx.commit();

    return true;
  } catch (const std::exception&) {
    // In case of any error, return false
    return false;
  }
