```cpp
#pragma once

#include <stdexcept>

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  if (amount <= 0.0) {
    return false;
  }

  // Open SQLite database "test_db.sqlite"
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  try {
    // Start a transaction (RAII – will rollback on destruction unless committed)
    sqlgen::Transaction tx(conn);

    // 1) Check if from_account has sufficient funds
    auto repository = sqlgen::make_repository<Account>();
    auto from_opt =
        repository.find_one(conn, sqlgen::where(&Account::account_id == from_account_id));

    if (!from_opt) {
      // Sender account does not exist – rollback by not committing
      return false;
    }

    Account from_account = *from_opt;
    if (from_account.balance < amount) {
      // Insufficient balance – rollback by not committing
      return false;
    }

    // 2) Deduct from sender
    from_account.balance -= amount;
    repository.update(conn, from_account);

    // 3) Add to receiver
    auto to_opt =
        repository.find_one(conn, sqlgen::where(&Account::account_id == to_account_id));
    if (!to_opt) {
      // Receiver account does not exist – rollback by not committing
      return false;
    }

    Account to_account = *to_opt;
    to_account.balance += amount;
    repository.update(conn, to_account);

    // 4) Commit transaction if everything succeeded
    tx.commit();
    return true;
  } catch (...) {
    // Any exception will cause the Transaction destructor to rollback.
    // We just ensure a clean false return.
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

