#pragma once

#include <filesystem>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

#include "eas_common.hpp"

namespace update_eas_table {

void update_eas_table() {
  // Ensure the database and all original tables exist first
  design_eas_database_with_major();

  using sqlgen::exec;

  auto res = sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add new column `Grade` to table `Score`, char(1), NOT NULL
        //    In SQLite this will be represented as TEXT with NOT NULL.
        return exec(conn,
                    "ALTER TABLE Score "
                    "ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'F';");
      })
      .and_then([](auto&& conn) {
        // 2. Modify the column type of `Age` in table `Student` to int,
        //    allowing NULL values.
        //    In SQLite, direct ALTER COLUMN is not supported; we recreate
        //    the table with the desired schema.
        //    The existing Student definition (in code) does not include Age,
        //    but the database is specified to have it; we follow the requirement
        //    and adjust the DB schema directly.
        //
        //    Steps:
        //      a. create a new table with desired schema
        //      b. copy data
        //      c. drop old table
        //      d. rename new table
        //    The columns we keep/copy: SNo, SName, Sex, Birthday, Major,
        //    Scorses, Remark, Age (converted as-is).
        std::string sql =
            "PRAGMA foreign_keys = OFF;"
            "BEGIN TRANSACTION;"
            "CREATE TABLE Student_new ("
            "  SNo VARCHAR(10) PRIMARY KEY,"
            "  SName VARCHAR(30) NOT NULL,"
            "  Sex INTEGER NOT NULL DEFAULT 1,"
            "  Birthday DATETIME,"
            "  Major INTEGER,"
            "  Scorses REAL,"
            "  Remark TEXT,"
            "  Age INTEGER"  // now INT, NULL allowed
            ");"
            "INSERT INTO Student_new (SNo, SName, Sex, Birthday, Major, Scorses, Remark, Age) "
            "  SELECT SNo, SName, Sex, Birthday, Major, Scorses, Remark, Age FROM Student;"
            "DROP TABLE Student;"
            "ALTER TABLE Student_new RENAME TO Student;"
            "COMMIT;"
            "PRAGMA foreign_keys = ON;";
        return exec(conn, sql);
      })
      .and_then([](auto&& conn) {
        // 3. Drop the table `Major`
        return exec(conn, "DROP TABLE IF EXISTS Major;");
      });

  // Propagate any error as an exception
  res.value();
}

} // namespace update_eas_table
