/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;

  // Connect to SQLite database "test_db.sqlite"
  sqlite::Database db{"test_db.sqlite"};

  // Table definitions for sqlgen
  constexpr auto departmentTable = make_table<Department>(
      "Department",
      make_column(&Department::department_id, "department_id"),
      make_column(&Department::name, "name"));

  constexpr auto projectTable = make_table<Project>(
      "Project",
      make_column(&Project::project_id, "project_id"),
      make_column(&Project::department_id, "department_id"),
      make_column(&Project::name, "name"));

  // In SQL, a RIGHT JOIN of Project onto Department:
  //
  //   SELECT Department.name, Project.name
  //   FROM Project
  //   RIGHT JOIN Department
  //     ON Project.department_id = Department.department_id;
  //
  // SQLite does not support RIGHT JOIN directly, but a RIGHT JOIN
  // can be expressed as a LEFT JOIN with the table order flipped:
  //
  //   SELECT Department.name, Project.name
  //   FROM Department
  //   LEFT JOIN Project
  //     ON Department.department_id = Project.department_id;
  //
  // To "simulate" RIGHT JOIN behavior while still using sqlgen's
  // expressive API, we perform this LEFT JOIN and map the results.

  std::vector<DepProj> result;

  db.read(
      select(
          departmentTable.col<&Department::name>(),
          projectTable.col<&Project::name>()),
      from(departmentTable)
          .left_join(projectTable,
                     departmentTable.col<&Department::department_id>() ==
                         projectTable.col<&Project::department_id>()),
      [&](const std::string &dept_name,
          const std::optional<std::string> &proj_name_opt) {
        DepProj dp;
        dp.department_name = dept_name;  // always present because Department is the left side
        // For departments without projects, proj_name_opt will be std::nullopt.
        // We propagate that by using an empty string for project_name while
        // keeping department_name populated so the department still appears.
        dp.project_name = proj_name_opt.value_or("");
        result.emplace_back(std::move(dp));
      });

  return result;
}

}  // namespace right_join_departments_projects
