  using namespace sqlgen;

  // SQLite dialect
  sqlite::Dialect dialect;

  // Register tables with sqlgen’s catalog for this dialect.
  // The exact API may differ slightly depending on sqlgen version; this
  // follows the typical pattern where you declare a schema/catalog.
  sqlite::Database db("test_db.sqlite");
  auto& catalog = db.catalog();

