  // JOIN B AS b ON b.a_id = a.id
  // WHERE b.score > 10 AND a.name LIKE '%x%'
  // ORDER BY b.score DESC
  // LIMIT 50;
  auto q = select(a.id, a.name, b.score)
             .from(a)
             .join(b, b.a_id == a.id)
             .where(b.score > 10.0 && a.name.like("%x%"))
             .order_by(desc(b.score))
