  // SQLite does not support DAY(), MONTH(), YEAR(), HOUR(), MINUTE(), SECOND(), WEEKDAY(), or
  // DAYS_BETWEEN() directly; instead we use strftime() and julianday() to emulate them:
  //
  // - Day:      CAST(strftime('%d', start_time) AS INTEGER)
  // - Month:    CAST(strftime('%m', start_time) AS INTEGER)
  // - Year:     CAST(strftime('%Y', start_time) AS INTEGER)
