    ta.event_name    = stmt.column_text(col++);
    ta.start_day     = stmt.column_int(col++);
    ta.start_month   = stmt.column_int(col++);
    ta.start_year    = stmt.column_int(col++);
    ta.start_hour    = stmt.column_int(col++);
    ta.start_minute  = stmt.column_int(col++);
    ta.start_second  = stmt.column_int(col++);
