bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;

  try {
    // Connect to the SQLite database "test_db.sqlite"
    sqlite::Database db("test_db.sqlite");

    // Get a connection (for SQLite this usually just wraps the same handle)
    auto conn = db.connection();

    // 1. Upsert items from vector input:
    //
    //    sqlgen's write API typically supports insert-or-replace via a mode flag.
    //    We use WriteMode::Replace, which generates "INSERT OR REPLACE" statements
    //    for rows whose primary key (item_id) may already exist.
    //
    //    This will:
    //    - INSERT a row if item_id does not exist yet
    //    - REPLACE the existing row if item_id already exists
    //
    //    We perform this in a transaction for atomicity.
    {
      Transaction tx(conn);

      for (const auto& item : items) {
        write<Inventory>(conn, item, WriteMode::Replace);
      }

      tx.commit();
    }

    // 2. Read back items to verify:
    //
    //    We fetch the rows with the same primary keys and ensure the data
    //    matches what we just wrote. If any mismatch occurs, we report failure.
    //
    //    Note: This is a simple verification; in real code you might rely on
    //    unit tests rather than runtime checks.
    for (const auto& item : items) {
      auto result = select<Inventory>(conn)
                        .where(c<&Inventory::item_id>() == item.item_id)
                        .execute();

      // We expect exactly one row for each item_id after upsert.
      if (result.size() != 1) {
        return false;
