  db.exec(R"SQL(
    CREATE TABLE IF NOT EXISTS "User" (
      user_id     INTEGER PRIMARY KEY,
      username    VARCHAR(50)  NOT NULL UNIQUE,
      email       VARCHAR(100) NOT NULL UNIQUE,
      join_date   DATETIME     NOT NULL,
      city        VARCHAR(50)
    );
  )SQL");

  db.exec(R"SQL(
    CREATE TABLE IF NOT EXISTS "Friendship" (
      user_id1        INTEGER NOT NULL,
      user_id2        INTEGER NOT NULL,
      friendship_date DATETIME NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES "User"(user_id),
      FOREIGN KEY (user_id2) REFERENCES "User"(user_id)
    );
  )SQL");

  // Clear existing data for a clean analysis run
  db.exec(R"SQL(DELETE FROM "Friendship";)SQL");
  db.exec(R"SQL(DELETE FROM "User";)SQL");

  // 2. Insert provided users and friendships into the database
  //
  // The in‑memory User has only user_id and username. For the missing fields,
  // we insert reasonable placeholder values so the schema constraints are met.
  {
    sqlite::Statement insert_user(
        db,
        R"SQL(
          INSERT INTO "User"(user_id, username, email, join_date, city)
          VALUES (?, ?, ?, ?, ?);
        )SQL");

    // Simple deterministic placeholder data
    for (const auto& u : users) {
      insert_user.reset();
      insert_user.bind(1, static_cast<int>(u.user_id.value));
      insert_user.bind(2, u.username);
      insert_user.bind(3, u.username + "@example.com");          // email
      insert_user.bind(4, std::string("2020-01-01 00:00:00"));   // join_date
      insert_user.bind(5, std::string("UnknownCity"));           // city
      insert_user.step();
    }
  }

  {
    sqlite::Statement insert_friendship(
        db,
        R"SQL(
          INSERT OR IGNORE INTO "Friendship"(user_id1, user_id2, friendship_date)
          VALUES (?, ?, ?);
        )SQL");

    for (const auto& f : friendships) {
      insert_friendship.reset();
      insert_friendship.bind(1, f.user1_id);
      insert_friendship.bind(2, f.user2_id);
      insert_friendship.bind(3, f.created_at.to_string());
