namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * The function connects to "test_db.sqlite" using sqlgen and operates on a table
 * that mirrors the OrderItem structure.
 *
 * Business logic:
 *   gross_total      = unit_price * quantity
 *   discounted_total = gross_total * (1 - COALESCE(discount_rate, 0)/100)
 *   final_total      = discounted_total * (1 + COALESCE(tax_rate, 0)/100)
 *   unit_cost        = gross_total / quantity
 *   quantity_group   = quantity % 10
 *   estimated_profit = unit_price * 0.3
 *
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;

  // Connect to SQLite database "test_db.sqlite"
  sqlite::Database db{"test_db.sqlite"};

  // Ensure schema for OrderItem exists and is in sync with struct
  // This creates (or updates) the table mapping based on the OrderItem struct.
  db.syncSchema<OrderItem>();

  // Use a transaction for bulk operations
  auto tx = db.transaction();

  // Clear existing data from the mapped table so we only analyze the provided items.
  // Table name is derived by sqlgen from the struct name (OrderItem -> "OrderItem").
  db.execute("DELETE FROM OrderItem;");

  // Insert provided items into the OrderItem table
  for (const auto& item : items) {
    db.insert(item);
  }

  tx.commit();

  // Now perform the analysis query using SQL arithmetic and aggregation
  const char* query = R"SQL(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0.0) AS discount_rate,
      COALESCE(tax_rate, 0.0) AS tax_rate,
      (unit_price * quantity) AS gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100.0)) AS discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100.0) * (1 + COALESCE(tax_rate, 0)/100.0)) AS final_total,
      (unit_price * quantity / quantity) AS unit_cost,
      (quantity % 10) AS quantity_group,
      (unit_price * 0.3) AS estimated_profit
    FROM OrderItem;
  )SQL";

  std::vector<OrderMetrics> results;
  db.query(
      query,
      [&](int item_id,
          int order_id,
          int product_id,
          double unit_price,
          int quantity,
          double discount_rate,
          double tax_rate,
          double gross_total,
          double discounted_total,
          double final_total,
          double unit_cost,
          int quantity_group,
          double estimated_profit) {
        OrderMetrics m{
            item_id,
            order_id,
            product_id,
            unit_price,
            quantity,
            discount_rate,
            tax_rate,
            gross_total,
            discounted_total,
            final_total,
            unit_cost,
            quantity_group,
            estimated_profit};
        results.push_back(m);
      });

  return results;
}

}  // namespace calculate_order_metrics

