bool inventory_bulk_write_and_read(const std::vector<Inventory>& items) {
  using namespace sqlgen;

  // Open SQLite database connection
  sqlite::Database db("test_db.sqlite");

  // Describe the Inventory table mapping for sqlgen
  auto inventoryTable = make_table(
      "Inventory",
