  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  try {
    // Connect to the SQLite database "test_db.sqlite"
    sqlgen::sqlite::connection conn("test_db.sqlite");

    // Create the Account table if it does not exist
    conn.execute(R"SQL(
      CREATE TABLE IF NOT EXISTS Account (
        account_id INTEGER PRIMARY KEY,
        balance REAL NOT NULL,
        status TEXT NOT NULL
      );
    )SQL");

    // Clear existing data to have a predictable state for this demo
    conn.execute("DELETE FROM Account;");

    // Insert some sample accounts using the write API
    {
      auto w = sqlgen::make_writer<Account>(conn);

      Account a1{sqlgen::PrimaryKey<int>{1}, 100.0, "active"};
      Account a2{sqlgen::PrimaryKey<int>{2}, 200.0, "active"};
      Account a3{sqlgen::PrimaryKey<int>{3}, 300.0, "inactive"};

      w.insert(a1);
      w.insert(a2);
      w.insert(a3);
    }

    // Perform update operations using set(...)

    // 1) Give account_id = 1 a new balance and status
    {
      auto w = sqlgen::make_writer<Account>(conn);
      w.update()
        .set(&Account::balance, 150.0)
        .set(&Account::status, std::string("active"))
        .where(&Account::account_id == 1)
        .execute();
    }

    // 2) Mark account_id = 2 as overdrawn and adjust balance
    {
      auto w = sqlgen::make_writer<Account>(conn);
      w.update()
        .set(&Account::balance, 50.0)
        .set(&Account::status, std::string("overdrawn"))
        .where(&Account::account_id == 2)
        .execute();
    }

    // 3) Reactivate and change balance for account_id = 3
    {
      auto w = sqlgen::make_writer<Account>(conn);
      w.update()
        .set(&Account::balance, 400.0)
        .set(&Account::status, std::string("active"))
        .where(&Account::account_id == 3)
        .execute();
    }

    // Verify changes persisted using the read API
    auto r = sqlgen::make_reader<Account>(conn);

    auto acc1_opt = r.get_one(&Account::account_id == 1);
    auto acc2_opt = r.get_one(&Account::account_id == 2);
    auto acc3_opt = r.get_one(&Account::account_id == 3);

    if (!acc1_opt || !acc2_opt || !acc3_opt) {
      return false;
    }

    const Account& acc1 = *acc1_opt;
    const Account& acc2 = *acc2_opt;
    const Account& acc3 = *acc3_opt;

    // Check expected values
    if (acc1.balance != 150.0 || acc1.status != "active") {
      return false;
    }

    if (acc2.balance != 50.0 || acc2.status != "overdrawn") {
      return false;
    }

    if (acc3.balance != 400.0 || acc3.status != "active") {
      return false;
    }

    return true;
  } catch (...) {
    // Any exception means the operation did not complete successfully
    return false;
  }
}

}  // namespace update_set_operations
