```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier
 * and the name of a product, if any.
 *
 * Demonstrates a FULL JOIN between Supplier and Product using SQLite, which does not
 * support FULL JOIN directly. We simulate FULL JOIN as:
 *
 *   (suppliers LEFT JOIN products)
 *   UNION
 *   (products LEFT JOIN suppliers WHERE supplier is NULL in the join result)
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Open (or create) the SQLite database.
  // The connection object manages the lifetime of the DB handle.
  Connection db{"test_db.sqlite"};

  // Make sure tables are mapped for sqlgen's ORM facilities (if needed elsewhere).
  // This does not create tables; it only describes mappings if already existing.
  mapTable<Supplier>("Supplier",
                     &Supplier::supplier_id, "supplier_id",
                     &Supplier::name,        "name");

  mapTable<Product>("Product",
                    &Product::product_id, "product_id",
                    &Product::supplier_id,"supplier_id",
                    &Product::name,       "name");

  // SQLite doesn't support FULL OUTER JOIN, so we emulate it with a UNION of:
  //
  // 1) Suppliers left-joined to products (all suppliers, matching products or NULL)
  // 2) Products left-joined to suppliers *where supplier is NULL* (products that
  //    don't have a matching supplier).
  //
  // We select the supplier name and product name so we can populate SupProd.
  //
  // Note: We alias the columns to `supplier_name` and `product_name` to simplify
  // extraction.

  const char* sql =
      "SELECT s.name AS supplier_name, p.name AS product_name "
      "FROM Supplier s "
      "LEFT JOIN Product p ON s.supplier_id = p.supplier_id "
      "UNION "
      "SELECT s2.name AS supplier_name, p2.name AS product_name "
      "FROM Product p2 "
      "LEFT JOIN Supplier s2 ON p2.supplier_id = s2.supplier_id "
      "WHERE s2.supplier_id IS NULL;";

  Statement stmt{db, sql};

  std::vector<SupProd> result;
  while (stmt.step()) {
    SupProd row;

    // Column 0: supplier_name (may be NULL in the second part of UNION if there’s no supplier)
    if (stmt.isNull(0)) {
      row.supplier_name = "";
    } else {
      row.supplier_name = stmt.get<std::string>(0);
    }

    // Column 1: product_name (may be NULL when no product is associated)
    if (stmt.isNull(1)) {
      row.product_name.reset();
    } else {
      row.product_name = stmt.get<std::string>(1);
    }

    result.push_back(std::move(row));
  }

  return result;
}

}  // namespace full_join_suppliers_products
```

