```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees_impl
 * Provides data-join analysis between Department and Employee input collections by
 * creating SQL tables in the SQLite database "test_db.sqlite", inserting the
 * provided rows, and executing a variety of join queries to produce
 * join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using namespace sqlgen;

  // Open connection to the SQLite database "test_db.sqlite"
  sqlite::connection conn("test_db.sqlite");

  // Create tables (if not exist) based on the Department and Employee structs
  // sqlgen will generate the appropriate CREATE TABLE statements.
  conn.create_table<Department>();
  conn.create_table<Employee>();

  // Clear existing data to ensure analysis uses only the provided collections.
  conn.delete_from<Department>().execute();
  conn.delete_from<Employee>().execute();

  // Insert provided Department rows
  for (const auto& d : depts) {
    conn.insert_into<Department>()
        .values(d)
        .execute();
  }

  // Insert provided Employee rows
  for (const auto& e : emps) {
    conn.insert_into<Employee>()
        .values(e)
        .execute();
  }

  JoinAnalysis analysis;

  // Helper lambda to convert a row into JoinResult
  auto make_join_result = [](const std::string* dept_name,
                             const std::string* first,
                             const std::string* last,
                             const double* sal) -> JoinResult {
    JoinResult jr;
    if (dept_name) jr.department_name = *dept_name;
    if (first) jr.first_name = *first;
    if (last) jr.last_name = *last;
    if (sal) jr.salary = *sal;
    return jr;
  };

  // Aliases for tables for readability
  auto d = table<Department>();
  auto e = table<Employee>();

  // 1. INNER JOIN: employees with assigned departments
  {
    auto rows = conn.select(d.department_name, e.first_name, e.last_name, e.salary)
                   .from(d)
                   .join(e, d.department_id == e.department_id)  // INNER JOIN
                   .execute();

    for (const auto& row : rows) {
      const auto& dept_name = std::get<0>(row);
      const auto& first = std::get<1>(row);
      const auto& last = std::get<2>(row);
      const auto& sal = std::get<3>(row);
      analysis.inner_join_results.push_back(
          make_join_result(&dept_name, &first, &last, &sal));
    }
  }

  // 2. LEFT JOIN: all employees, even without departments
  {
    auto rows = conn.select(d.department_name, e.first_name, e.last_name, e.salary)
                   .from(e)
                   .left_join(d, e.department_id == d.department_id)
                   .execute();

    for (const auto& row : rows) {
      const auto& dept_name_opt = std::get<0>(row);
      const auto& first = std::get<1>(row);
      const auto& last = std::get<2>(row);
      const auto& sal = std::get<3>(row);

      const std::string* dept_ptr = dept_name_opt ? &*dept_name_opt : nullptr;
      analysis.left_join_results.push_back(
          make_join_result(dept_ptr, &first, &last, &sal));
    }
  }

  // 3. RIGHT JOIN: all departments, even without employees
  // SQLite does not support RIGHT JOIN directly, so we emulate it as:
  // RIGHT JOIN Employee e ON e.department_id = d.department_id
  //   == LEFT JOIN e ON e.department_id = d.department_id starting from Department
  {
    auto rows = conn.select(d.department_name, e.first_name, e.last_name, e.salary)
                   .from(d)
                   .left_join(e, d.department_id == e.department_id)
                   .execute();

    for (const auto& row : rows) {
      const auto& dept_name = std::get<0>(row);
      const auto& first_opt = std::get<1>(row);
      const auto& last_opt = std::get<2>(row);
      const auto& sal_opt = std::get<3>(row);

      const std::string* first_ptr = first_opt ? &*first_opt : nullptr;
      const std::string* last_ptr  = last_opt  ? &*last_opt  : nullptr;
      const double* sal_ptr        = sal_opt   ? &*sal_opt   : nullptr;

      analysis.right_join_results.push_back(
          make_join_result(&dept_name, first_ptr, last_ptr, sal_ptr));
    }
  }

  // 4. FULL JOIN: all employees and all departments
  // SQLite does not support FULL OUTER JOIN. We emulate as UNION of:
  //  - LEFT JOIN (departments as left)
  //  - LEFT JOIN (employees as left) where no matching department
  //
  // First part: all departments (with matching employees if any)
  {
    auto rows = conn.select(d.department_name, e.first_name, e.last_name, e.salary)
                   .from(d)
                   .left_join(e, d.department_id == e.department_id)
                   .execute();

    for (const auto& row : rows) {
      const auto& dept_name = std::get<0>(row);
      const auto& first_opt = std::get<1>(row);
      const auto& last_opt = std::get<2>(row);
      const auto& sal_opt = std::get<3>(row);

      const std::string* first_ptr = first_opt ? &*first_opt : nullptr;
      const std::string* last_ptr  = last_opt  ? &*last_opt  : nullptr;
      const double* sal_ptr        = sal_opt   ? &*sal_opt   : nullptr;

      analysis.full_join_results.push_back(
          make_join_result(&dept_name, first_ptr, last_ptr, sal_ptr));
    }
  }

  // Second part: employees that did not match any department
  {
    auto rows = conn.select(d.department_name, e.first_name, e.last_name, e.salary)
                   .from(e)
                   .left_join(d, e.department_id == d.department_id)
                   .where(is_null(d.department_id))
                   .execute();

    for (const auto& row : rows) {
      const auto& dept_name_opt = std::get<0>(row);
      const auto& first = std::get<1>(row);
      const auto& last = std::get<2>(row);
      const auto& sal = std::get<3>(row);

