```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;         // 0 = Sunday, 1 = Monday, ..., 6 = Saturday (SQLite strftime('%w'))
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;

  // Open SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // Register the Sales table with sqlgen
  auto salesTable = make_table<Sales>("Sales");

  // Vector to hold results
  std::vector<WeekdayStats> results;

  // Use a raw query to leverage SQLite's strftime to extract weekday.
  // strftime('%w', sale_time) returns: 0 = Sunday, 1 = Monday, ..., 6 = Saturday.
  //
  // We only need two columns in the result:
  //   weekday  (as integer)
  //   total_quantity (sum of quantity)
  //
  // Note: We rely on sqlgen's query interface to map columns by index.
  auto stmt = db.prepare(
      "SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday, "
      "       SUM(quantity) AS total_quantity "
      "FROM Sales "
      "GROUP BY weekday "
      "ORDER BY weekday ASC");

  // Execute and read rows
  while (stmt.step()) {
    WeekdayStats ws;
    ws.weekday = stmt.get<int>(0);
    ws.total_quantity = stmt.get<int>(1);
    results.push_back(ws);
  }

  return results;
}

}  // namespace weekday_sales_analysis
```

