  //   "User".user_id,
  //   "User".name,
  //   COUNT(Post.post_id) AS post_count,
  //   AVG(LENGTH(Post.content)) AS avg_length
  // FROM User
  // LEFT JOIN Post ON User.user_id = Post.user_id
  // GROUP BY User.user_id, User.name;
  //
  // Notes:
  // - LEFT JOIN so users without posts are still returned with post_count = 0
  //   and avg_length = NULL (mapped to std::optional<double>).
  // - We group by user_id and name to get per-user aggregates.

  using U = User;
  using P = Post;
  using S = Stats;

  auto q = mapper.makeQuery<S>()
              .select(
                  sqlgen::column<U>(&U::user_id),
                  sqlgen::column<U>(&U::name),
                  sqlgen::count(sqlgen::column<P>(&P::post_id)),
                  sqlgen::avg(
                      sqlgen::function<int>("length",
                                             sqlgen::column<P>(&P::content))))
              .from<U>()
              .leftJoin<P>(
                  sqlgen::on(sqlgen::column<U>(&U::user_id) ==
                             sqlgen::column<P>(&P::user_id)))
              .groupBy(
                  sqlgen::column<U>(&U::user_id),
                  sqlgen::column<U>(&U::name));

  return q.exec(conn);
}

}  // namespace group_by_with_aggregations

